import type { Metadata } from "next";
import Link from "next/link";
import { notFound } from "next/navigation";
import type { BlogPost, Comment } from "@/types/blog";

export const revalidate = 300;

type BlogPostPageProps = {
  params: Promise<{
    id: string;
  }>;
};

async function fetchPost(id: string): Promise<BlogPost> {
  const response = await fetch(
    `https://jsonplaceholder.typicode.com/posts/${id}`,
    {
      next: { revalidate },
    }
  );

  if (!response.ok) {
    throw new Error("Failed to load post");
  }

  return (await response.json()) as BlogPost;
}

async function fetchComments(id: string): Promise<Comment[]> {
  const response = await fetch(
    `https://jsonplaceholder.typicode.com/posts/${id}/comments`,
    {
      next: { revalidate },
    }
  );

  if (!response.ok) {
    throw new Error("Failed to load comments");
  }

  return (await response.json()) as Comment[];
}

export async function generateStaticParams() {
  const response = await fetch("https://jsonplaceholder.typicode.com/posts", {
    next: { revalidate },
  });

  if (!response.ok) {
    return [];
  }

  const posts = (await response.json()) as BlogPost[];

  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
}

export async function generateMetadata({
  params,
}: BlogPostPageProps): Promise<Metadata> {
  const { id } = await params;

  try {
    const post = await fetchPost(id);

    return {
      title: post.title,
      description: post.body.substring(0, 160),
      openGraph: {
        title: post.title,
        description: post.body.substring(0, 160),
      },
    };
  } catch {
    return {
      title: "Post not found",
    };
  }
}

export default async function BlogPostPage({ params }: BlogPostPageProps) {
  const { id } = await params;

  try {
    const [post, comments] = await Promise.all([
      fetchPost(id),
      fetchComments(id),
    ]);

    return (
      <article>
        <Link href="/blog" className="button-link">
          ← Back
        </Link>

        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map((comment) => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    );
  } catch {
    notFound();
  }
}

