import { NextResponse } from "next/server";
import type { ApiPost, UpdatePostBody } from "@/types/blog";

type RouteContext = {
  params: Promise<{
    id: string;
  }>;
};

export async function GET(_: Request, { params }: RouteContext) {
  const { id } = await params;
  const post: ApiPost = {
    id: Number.parseInt(id, 10),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(request: Request, { params }: RouteContext) {
  const { id } = await params;
  const body = (await request.json()) as UpdatePostBody;

  const updatedPost: ApiPost = {
    id: Number.parseInt(id, 10),
    title: body.title || `Post ${id}`,
    content: body.content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(_: Request, { params }: RouteContext) {
  const { id } = await params;

  return NextResponse.json({
    message: `Post ${id} deleted successfully`,
  });
}

